                    int getfrag, void *from, int length, int offset,
                    int more, unsigned int flags, struct rtable *rt,
                    struct dst_entry *dst)
{
    struct ip_options *opt = NULL;
    struct iphdr *iph;
    struct tcphdr *tcph;
    int err;

    // Check if the socket buffer is large enough
    if (skb_tailroom(skb) < sizeof(struct iphdr) + sizeof(struct tcphdr)) {
        err = -ENOMEM;
        goto out;
    }

    // Allocate memory for the IP header
    iph = skb_put(skb, sizeof(struct iphdr));
    memset(iph, 0, sizeof(struct iphdr));

    // Set up the IP header
    iph->version = 4;
    iph->ihl = 5; // Minimum header length
    iph->tos = 0;
    iph->tot_len = htons(skb->len);
    iph->id = htons(0); // Kernel will fill this in
    iph->frag_off = htons(0);
    iph->ttl = 64;
    iph->protocol = IPPROTO_TCP;
    iph->check = 0; // Kernel will calculate this
    iph->saddr = rt->rt_src;
    iph->daddr = rt->rt_dst;

    // Allocate memory for the TCP header
    tcph = skb_put(skb, sizeof(struct tcphdr));
    memset(tcph, 0, sizeof(struct tcphdr));

    // Set up the TCP header
    tcph->source = htons(sk->sk_num);
    tcph->dest = htons(msg->msg_name->sa_family == AF_INET ? ((struct sockaddr_in *)msg->msg_name)->sin_port : 0);
    tcph->seq = htonl(sk->sk_sequence);
    tcph->ack_seq = htonl(sk->sk_ack_backlog);
    tcph->doff = 5; // Minimum header length
    tcph->fin = 0;
    tcph->syn = 1; // This is a SYN packet
    tcph->rst = 0;
    tcph->psh = 0;
    tcph->ack = 0;
    tcph->urg = 0;
    tcph->window = htons(65535);
    tcph->check = 0; // Kernel will calculate this
    tcph->urg_ptr = 0;

    // Set the socket options
    if (msg->msg_flags & MSG_DONTWAIT)
        flags |= MSG_DONTWAIT;
    if (msg->msg_flags & MSG_CONFIRM)
        flags |= MSG_CONFIRM;
    if (msg->msg_flags & MSG_ERRQUEUE)
        flags |= MSG_ERRQUEUE;

    // Append the data to the socket buffer
    err = skb_append_data(skb, getfrag, from, length, offset, more, flags);
    if (err)
        goto out;

    // Calculate the checksums
    iph->check = ip_fast_csum((unsigned char *)iph, iph->ihl);
    tcph->check = csum_tcpudp_magic(iph->saddr, iph->daddr, skb->len, IPPROTO_TCP, csum_partial(tcph, skb->len, 0));

out:
    return err;
}
