#include <linux/list.h>
#include <linux/spinlock.h>
#include <linux/usb/chipidea.h>
#include <linux/usb/gadget.h>

struct dwc3_request {
    struct list_head queue;
    struct usb_request req;
    struct dwc3 *dwc;
    struct dwc3_ep *dep;
    struct dwc3_gadget_ep *dep_gadget;
    bool is_mapped;
    bool is_processed;
};

static void dwc3_gadget_giveback(struct dwc3 *dwc, struct dwc3_ep *dep, struct dwc3_request *req)
{
    struct usb_request *usb_req = &req->req;
    unsigned long flags;

    spin_lock_irqsave(&dwc->lock, flags);

    // Check if the request is already processed
    if (req->is_processed) {
        spin_unlock_irqrestore(&dwc->lock, flags);
        return;
    }

    // Mark the request as processed
    req->is_processed = true;

    // Unmap the request if it was mapped
    if (req->is_mapped) {
        usb_gadget_unmap_request_by_dev(&dwc->gadget, usb_req);
        req->is_mapped = false;
    }

    // Remove the request from the queue
    list_del(&req->queue);

    // Call the completion handler for the USB request
    usb_req->complete(usb_req);

    spin_unlock_irqrestore(&dwc->lock, flags);
}
```

