// Function to securely decrypt ESP packets
int esp_input(void *ctx, struct sk_buff *skb, struct esp_hdr *esp, int encap)
{
    struct scatterlist sg_in[3], sg_out[3];
    unsigned char *iv, *assoc_data, *ciphertext;
    int ciphertext_len, decrypted_len;

    // Initialize scatter-gather lists
    sg_init_table(sg_in, 3);
    sg_init_table(sg_out, 3);

    // Prepare scatter-gather lists for input and output
    sg_set_buf(&sg_in[0], esp->data, esp->data_len);
    sg_set_buf(&sg_in[1], esp->iv, ESP_IV_LEN);
    sg_set_buf(&sg_in[2], esp->auth_tag, ESP_AUTH_TAG_LEN);
    sg_set_buf(&sg_out[0], esp->data, esp->data_len);

    // Set up initialization vector, associated data, and ciphertext
    iv = esp->iv;
    assoc_data = esp->data;
    ciphertext = esp->data;

    // Set the length of the ciphertext
    ciphertext_len = esp->data_len;

    // Decrypt the ESP packet
    decrypted_len = crypto_aead_decrypt(&ctx->crypto_tfm, sg_out, &ciphertext_len,
                                      sg_in, 3, iv, ESP_IV_LEN,
                                      assoc_data, esp->data_len,
                                      esp->auth_tag, ESP_AUTH_TAG_LEN);

    if (decrypted_len < 0) {
        fprintf(stderr, "Failed to decrypt ESP packet: %d\n", decrypted_len);
        return -1;
    }

    // Update the length of the data in the scatter-gather list
    sg_out[0].length = decrypted_len;

    // Update the length of the data in the skb
    skb_put(skb, decrypted_len);

    return 0;
}
