// Define the Node structure
struct Node {
    std::string type;
    std::string address;
    int port;
    std::string subscription;
};

// Define the Config structure
struct Config {
    std::string socksPattern;
    std::string httpPattern;
    std::string filePattern;
    std::unordered_map<std::string, std::string> subscriptions;
};

// Function to process and categorize network links
void addNodes(const Config& config, const std::string& input, std::vector<Node>& nodes) {
    std::regex socksRegex(config.socksPattern);
    std::regex httpRegex(config.httpPattern);
    std::regex fileRegex(config.filePattern);

    std::istringstream iss(input);
    std::string line;

    while (std::getline(iss, line)) {
        if (std::regex_match(line, socksRegex)) {
            // Process SOCKS link
            Node node;
            node.type = "SOCKS";
            // Extract address and port from the line
            // ...
            nodes.push_back(node);
        } else if (std::regex_match(line, httpRegex)) {
            // Process HTTP link
            Node node;
            node.type = "HTTP";
            // Extract address and port from the line
            // ...
            nodes.push_back(node);
        } else if (std::regex_match(line, fileRegex)) {
            // Process local file link
            Node node;
            node.type = "FILE";
            // Extract address and port from the line
            // ...
            nodes.push_back(node);
        } else {
            // Log error for unrecognized link type
            std::cerr << "Error: Unrecognized link type in line: " << line << std::endl;
        }
    }
}

// Function to filter nodes based on subscription data
void filterNodes(const std::unordered_map<std::string, std::string>& subscriptions, std::vector<Node>& nodes) {
    for (auto& node : nodes) {
        if (subscriptions.find(node.subscription) == subscriptions.end()) {
            // Remove node if it does not match any subscription
            nodes.erase(std::remove(nodes.begin(), nodes.end(), node), nodes.end());
        }
    }
}

int main() {
    // Example usage
    Config config = {
        "socks:\\s*(\\S+)\\s*(\\d+)",
        "http:\\s*(\\S+)\\s*(\\d+)",
        "file:\\s*(\\S+)",
        {
            {"sub1", "user1"},
            {"sub2", "user2"}
        }
    };

    std::string input = "socks:127.0.0.1 1080\nhttp:www.example.com 80\nfile:local.txt\nsocks:192.168.1.1 1080\n";
    std::vector<Node> nodes;

    addNodes(config, input, nodes);
    filterNodes(config.subscriptions, nodes);

    for (const auto& node : nodes) {
        std::cout << "Node type: " << node.type << ", Address: " << node.address << ", Port: " << node.port << ", Subscription: " << node.subscription << std::endl;
    }

    return 0;
}
