#include <assert.h>

// Define the mode flags
enum Mode {
    MODE_DEFAULT = 0,
    MODE_VERBOSE,
    MODE_DEBUG
};

// Function to parse command-line arguments
void parse_args(int argc, char *argv[], enum Mode *mode, char **env_var) {
    int opt;
    static struct option long_options[] = {
        {"mode", required_argument, NULL, 'm'},
        {"env", required_argument, NULL, 'e'},
        {0, 0, 0, 0}
    };

    // Initialize mode to default
    *mode = MODE_DEFAULT;

    // Parse command-line options
    while ((opt = getopt_long(argc, argv, "m:e:", long_options, NULL)) != -1) {
        switch (opt) {
            case 'm':
                if (strcmp(optarg, "verbose") == 0) {
                    *mode = MODE_VERBOSE;
                } else if (strcmp(optarg, "debug") == 0) {
                    *mode = MODE_DEBUG;
                } else {
                    fprintf(stderr, "Invalid mode: %s\n", optarg);
                    exit(EXIT_FAILURE);
                }
                break;
            case 'e':
                *env_var = strdup(optarg);
                if (*env_var == NULL) {
                    perror("strdup");
                    exit(EXIT_FAILURE);
                }
                break;
            default:
                fprintf(stderr, "Usage: %s [-m mode] [-e env_var]\n", argv[0]);
                exit(EXIT_FAILURE);
        }
    }

    // Validate input
    assert(*mode >= MODE_DEFAULT && *mode <= MODE_DEBUG);
    assert(*env_var != NULL);
}

int main(int argc, char *argv[]) {
    enum Mode mode;
    char *env_var;

    // Parse command-line arguments
    parse_args(argc, argv, &mode, &env_var);

    // Use the parsed values
    printf("Mode: %d\n", mode);
    printf("Environment Variable: %s\n", env_var);

    // Free allocated memory
    free(env_var);

    return 0;
}
