struct ImapAccount *imap_open_connection(struct ImapAccount *ia, const char *host, int port)
{
    struct ImapAccount *imap_account = NULL;
    struct sockaddr_in serv_addr;
    int sockfd;

    // Allocate memory for the ImapAccount structure
    imap_account = malloc(sizeof(struct ImapAccount));
    if (!imap_account) {
        perror("Failed to allocate memory for ImapAccount");
        return NULL;
    }

    // Initialize the socket
    sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd < 0) {
        perror("Failed to open socket");
        free(imap_account);
        return NULL;
    }

    // Set up the server address
    memset(&serv_addr, 0, sizeof(serv_addr));
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_port = htons(port);

    // Convert the host name to an IP address
    if (inet_pton(AF_INET, host, &serv_addr.sin_addr) <= 0) {
        perror("Invalid address/ Address not supported");
        close(sockfd);
        free(imap_account);
        return NULL;
    }

    // Connect to the server
    if (connect(sockfd, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
        perror("Connection failed");
        close(sockfd);
        free(imap_account);
        return NULL;
    }

    // Initialize the ImapAccount structure
    imap_account->sockfd = sockfd;
    imap_account->host = strdup(host);
    imap_account->port = port;

    // Perform the STARTTLS command
    if (!imap_cmd_step(imap_account, "STARTTLS")) {
        perror("STARTTLS command failed");
        close(sockfd);
        free(imap_account);
        return NULL;
    }

    // Start TLS
    if (!mutt_ssl_starttls(imap_account->sockfd)) {
        perror("Failed to start TLS");
        close(sockfd);
        free(imap_account);
        return NULL;
    }

    return imap_account;
}
