        krb_principal_name = (char *)malloc(strlen(principal_name) + strlen("@") + strlen(PRINCIPAL_REALM) + 1);
        sprintf(krb_principal_name, "%s@%s", principal_name, PRINCIPAL_REALM);
        krb_login_failed_count = (char *)"0";
        krb_last_pwd_change = (char *)"0";

        // Add attributes
        struct berval add_attrs[] = {
            { (char *)"krbprincipalname", 1, (struct berval *)&krb_principal_name },
            { (char *)"krbLoginFailedCount", 1, (struct berval *)&krb_login_failed_count },
            { (char *)"krbLastPwdChange", 1, (struct berval *)&krb_last_pwd_change },
