        link = rpmfiFL(fi);
        content = rpmfiFC(fi);

        // Check if the entry is a file
        if (rpmfiFT(fi) == RPMFILE_REG) {
            // Create the directory if it doesn't exist
            if (stat(name, &st) != 0 && mkdir(name, 0755) != 0) {
                perror("mkdir");
                rc = RPMRC_FAIL;
                break;
            }

            // Create the file
            fd = open(name, O_WRONLY | O_CREAT | O_TRUNC, 0644);
            if (fd == -1) {
                perror("open");
                rc = RPMRC_FAIL;
                break;
            }

            // Write the content to the file
            if (write(fd, content, strlen(content)) != strlen(content)) {
                perror("write");
                close(fd);
                rc = RPMRC_FAIL;
                break;
            }

            close(fd);
        } else if (rpmfiFT(fi) == RPMFILE_LINK) {
            // Create the hardlink
            if (link == NULL) {
                fprintf(stderr, "Hardlink target missing for file: %s\n", name);
                rc = RPMRC_FAIL;
                break;
            }

            if (symlink(link, name) != 0) {
