#include <openssl/ssl.h>
#include <openssl/err.h>
#include <string.h>

int ssl3_get_server_hello(SSL *s) {
    unsigned char *p = s->s3->rbuf.buf;
    int n, i;
    unsigned char *session_id;
    int session_id_length;
    unsigned int cipher_suite;
    int compression_method;

    // Check if the buffer has enough data to read the ServerHello message
    if (s->s3->rbuf.left < SSL3_SERVER_HELLO_LEN) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the length of the session ID
    n = SSL3_NUM1BYTE;
    session_id_length = *(p++);
    session_id = p;

    // Ensure the session ID length does not exceed the maximum allowed
    if (session_id_length > SSL_MAX_SSL_SESSION_ID_LENGTH) {
        return SSL_ERROR_SSL;
    }

    // Move past the session ID
    p += session_id_length;

    // Read the cipher suite
    n = SSL3_NUM2BYTES;
    cipher_suite = (p[0] << 8) | p[1];
    p += n;

    // Read the compression method
    compression_method = *p++;

    // Validate the cipher suite
    if (!SSL_CIPHER_get_by_value(cipher_suite)) {
        return SSL_ERROR_SSL;
    }

    // Update the SSL state with the parsed information
    s->session->session_id_length = session_id_length;
    memcpy(s->session->session_id, session_id, session_id_length);
    s->session->cipher = SSL_CIPHER_get_by_value(cipher_suite);
    s->session->compression_method = compression_method;

    return SSL_SUCCESS;
}
