#include <QZipReader>
#include <QTextCodec>
#include <QDebug>

bool UnZip(const QString &zipPath, const QString &extractPath)
{
    if (!QFile::exists(zipPath)) {
        qDebug() << "Zip file does not exist:" << zipPath;
        return false;
    }

    QZipReader zipReader(zipPath);
    if (!zipReader.open()) {
        qDebug() << "Failed to open zip file:" << zipPath;
        return false;
    }

    QDir extractDir(extractPath);
    if (!extractDir.exists()) {
        if (!extractDir.mkpath(".")) {
            qDebug() << "Failed to create extraction directory:" << extractPath;
            return false;
        }
    }

    QCodePage437Codec codec;

    for (const QZipFileInfo &entryInfo : zipReader.fileInfoList()) {
        QString entryName = codec.toUnicode(entryInfo.filePath());
        QString fullPath = extractPath + "/" + entryName;

        if (entryInfo.isDir()) {
            if (!QDir(fullPath).mkpath(".")) {
                qDebug() << "Failed to create directory:" << fullPath;
                return false;
            }
        } else {
            QFile file(fullPath);
            if (!file.open(QIODevice::WriteOnly)) {
                qDebug() << "Failed to open file for writing:" << fullPath;
                return false;
            }

            QByteArray data = zipReader.fileData(entryInfo.filePath());
            file.write(data);
            file.close();
        }
    }

    zipReader.close();
    return true;
}
