// Function to securely write PALM image files using MagickCore APIs
static MagickBooleanType WritePALMImage(const ImageInfo *image_info, Image *image)
{
    ExceptionInfo *exception = AcquireExceptionInfo();
    MagickBooleanType status = MagickFalse;
    char *buffer = NULL;
    size_t size = 0;

    // Initialize the image for writing
    status = WriteImage(image_info, image);
    if (status == MagickFalse)
    {
        goto cleanup;
    }

    // Allocate memory for the buffer
    size = GetBlobSize(image);
    buffer = (char *)malloc(size * sizeof(char));
    if (buffer == NULL)
    {
        ThrowException(exception, ResourceLimitError, MemoryAllocationFailed, NULL);
        goto cleanup;
    }

    // Copy the image data into the buffer
    CopyBlobToBuffer(image, buffer, size);

    // Write the buffer to the output file
    FILE *file = fopen(image_info->filename, "wb");
    if (file == NULL)
    {
        ThrowException(exception, FileOpenError, UnableToOpenFile, image_info->filename);
        goto cleanup;
    }
    fwrite(buffer, 1, size, file);
    fclose(file);

    // Free the buffer and release the image
    free(buffer);
    status = MagickTrue;

cleanup:
    if (buffer != NULL)
    {
        free(buffer);
    }
    if (image != NULL)
    {
        DestroyImage(image);
    }
    if (exception != NULL)
    {
        DestroyExceptionInfo(exception);
    }

    return status;
}
