#include <Eigen/Dense>
#include <random>
#include <iostream>

// Function to perform vectorized uniform rejection sampling
Eigen::MatrixXd vectorizedUniformRejectionSampling(int batchSize, int sampleSize, double lowerBound, double upperBound) {
    // Initialize PhiloxRandom generator
    std::random_device rd;
    std::mt19937 gen(rd());
    Eigen::PhiloxRandom philox(gen, 1);

    // Initialize matrix to store samples
    Eigen::MatrixXd samples(batchSize, sampleSize);

    // Perform rejection sampling
    for (int i = 0; i < batchSize; ++i) {
        for (int j = 0; j < sampleSize; ++j) {
            double u;
            do {
                u = philox.randomDouble();
            } while (u < lowerBound || u > upperBound);
            samples(i, j) = u;
        }
    }

    return samples;
}

int main() {
    // Example usage
    int batchSize = 5;
    int sampleSize = 10;
    double lowerBound = 0.0;
    double upperBound = 1.0;

    Eigen::MatrixXd samples = vectorizedUniformRejectionSampling(batchSize, sampleSize, lowerBound, upperBound);

    // Print sampled values
    std::cout << "Sampled values:\n" << samples << std::endl;

    return 0;
}
