using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

void run(const std::string& uri, const std::string& username, const std::string& password, const std::string& role, const std::string& db_name) {
    mongocxx::instance inst{};
    mongocxx::client client{mongocxx::uri{uri}};

    // Connect to the specified database
    auto db = client[db_name];

    // Check if the user already exists
    auto users_collection = db["system.users"];
    auto filter = make_document(kvp("user", username));
    auto user_exists = users_collection.find_one(filter.view()).ok();

    if (user_exists) {
        // Update the user's password and roles
        auto update_filter = make_document(kvp("user", username));
        auto update_doc = make_document(kvp("$set", make_document(kvp("pwd", password), kvp("roles", make_document(kvp("role", role), kvp("db", db_name))))));
        users_collection.update_one(update_filter.view(), update_doc.view());
    } else {
        // Create a new user with the specified credentials and roles
        auto user_doc = make_document(kvp("user", username), kvp("pwd", password), kvp("roles", make_document(kvp("role", role), kvp("db", db_name))));
        users_collection.insert_one(user_doc.view());
    }

    std::cout << "User " << username << " created or updated successfully." << std::endl;
}

int main() {
    std::string uri = "mongodb://localhost:27017";
    std::string username = "newuser";
    std::string password = "newpassword";
