    if (retval) {
        krb5_free_principal(handle->context, principal);
        return retval;
    }

    /* Generate new keys for the principal */
    new_keys = (krb5_keyblock *)malloc(sizeof(krb5_keyblock) * KADM5_MAX_KEYS);
    if (!new_keys) {
        kadm5_free_entry(handle, entry);
        krb5_free_principal(handle->context, principal);
        return ENOMEM;
    }

    for (i = 0; i < KADM5_MAX_KEYS; i++) {
        retval = krb5_generate_random_key(handle->context, enctype, &new_keys[i]);
        if (retval) {
            free(new_keys);
            kadm5_free_entry(handle, entry);
            krb5_free_principal(handle->context, principal);
            return retval;
        }
    }

    /* Apply the new keys to the principal's entry */
    for (i = 0; i < KADM5_MAX_KEYS; i++) {
        retval = krb5_dbe_crk(handle->context, entry, &new_keys[i]);
        if (retval) {
            free(new_keys);
            kadm5_free_entry(handle, entry);
            krb5_free_principal(handle->context, principal);
            return retval;
        }
    }

    /* Update the entry in the database */
    retval = kdb_put_entry(handle->context, entry);
    if (retval) {
        free(new_keys);
        kadm5_free_entry(handle, entry);
        krb5_free_principal(handle->context, principal);
        return retval;
    }

    /* Free resources */
    free(new_keys);
    kadm5_free_entry(handle, entry);
    krb5_free_principal(handle->context, principal);

    return 0;
}
