typedef struct {
    char *filename;
    char *temp_filename;
    FILE *fp;
    int fd;
    struct stat file_stat;
} LogState;

int writeState(LogState *state, const char *new_state) {
    // Open the temporary file for writing
    state->fd = open(state->temp_filename, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (state->fd == -1) {
        perror("Failed to open temporary file");
        return -1;
    }

    // Write the new state to the temporary file
    if (write(state->fd, new_state, strlen(new_state)) == -1) {
        perror("Failed to write to temporary file");
        close(state->fd);
        return -1;
    }

    // Flush the file descriptor to ensure data is written to disk
    if (fsync(state->fd) == -1) {
        perror("Failed to sync temporary file");
        close(state->fd);
        return -1;
    }

    // Close the file descriptor
    close(state->fd);

    // Open the original log file to get its current state
    state->fd = open(state->filename, O_RDONLY);
    if (state->fd == -1) {
        perror("Failed to open original log file");
        return -1;
    }

    // Get the status of the original log file
    if (fstat(state->fd, &state->file_stat) == -1) {
        perror("Failed to get file status");
        close(state->fd);
        return -1;
    }

    // Close the file descriptor
    close(state->fd);

    // Rename the temporary file to the original file name
    if (rename(state->temp_filename, state->filename) == -1) {
        perror("Failed to rename temporary file");
        return -1;
    }

    // Open the renamed file for reading
    state->fp = fdopen(state->fd, "r");
    if (state->fp == NULL) {
        perror("Failed to open renamed file");
        return -1;
    }

    return 0;
