namespace reference_ops {

template <typename T>
void AveragePool(const PoolParams& params, const RuntimeShape& input_shape,
                 const T* input_data, const RuntimeShape& output_shape,
                 T* output_data) {
  const int batches = input_shape.Dims(0);
  const int height = input_shape.Dims(1);
  const int width = input_shape.Dims(2);
  const int channels = input_shape.Dims(3);
  const int kernel_height = params.filter_height;
  const int kernel_width = params.filter_width;
  const int stride_height = params.stride_height;
  const int stride_width = params.stride_width;
  const Padding padding = params.padding;
  const float output_activation_min = params.quantized_activation_min;
  const float output_activation_max = params.quantized_activation_max;

  // Calculate the output dimensions based on padding
  const int output_height = (height + 2 * params.padding_value - kernel_height) / stride_height + 1;
  const int output_width = (width + 2 * params.padding_value - kernel_width) / stride_width + 1;

  // Initialize the output tensor
  for (int b = 0; b < batches; ++b) {
    for (int h = 0; h < output_height; ++h) {
      for (int w = 0; w < output_width; ++w) {
        for (int c = 0; c < channels; ++c) {
          int input_h = h * stride_height - params.padding_value;
          int input_w = w * stride_width - params.padding_value;
          float sum = 0.0f;
          int count = 0;
          // Check if the kernel is within the input bounds
          if (input_h >= 0 && input_h + kernel_height <= height &&
              input_w >= 0 && input_w + kernel_width <= width) {
            for (int kh = 0; kh < kernel_height; ++kh) {
              for (int kw = 0; kw < kernel_width; ++kw) {
                sum += static_cast<float>(input_data[b * height * width * channels +
                                                     (input_h + kh) * width * channels +
                                                     (input_w + kw) * channels + c]);
                count++;
              }
            }
          }
          // Calculate the average and clamp the output value
          float average = sum / count;
          output_data[b * output_height * output_width * channels +
                      h * output_width * channels +
                      w * channels + c] =
              std::max(std::min(average, output_activation_max), output_activation_min);
        }
      }
    }
  }
}

