namespace tensorflow {

class SafeMap {
public:
    SafeMap(int max_size) : max_size_(max_size), current_size_(0) {}

    // Function to safely insert or update a tuple in the map
    Status SafeInsertOrUpdate(const Tensor& key, const Tensor& value) {
        mutex_lock lock(mutex_);
        if (current_size_ >= max_size_) {
            return errors::ResourceExhausted("Memory limit exceeded");
        }
        if (map_.find(key.scalar<int32>()()) != map_.end()) {
            map_[key.scalar<int32>()()] = value;
        } else {
            map_.insert({key.scalar<int32>()(), value});
            current_size_++;
        }
        return Status::OK();
    }

    // Function to safely retrieve a value from the map
    Status SafeRetrieve(const Tensor& key, Tensor* value) {
        mutex_lock lock(mutex_);
        if (map_.find(key.scalar<int32>()()) != map_.end()) {
            *value = map_[key.scalar<int32>()()];
            return Status::OK();
        } else {
            return errors::NotFound("Key not found");
        }
    }

private:
    mutex mutex_;
    std::map<int32, Tensor> map_;
    int max_size_;
    int current_size_;
};

}  // namespace tensorflow
```

