int ssl3_get_server_hello(SSL *s) {
    int n, al;
    unsigned char *p;
    unsigned int len;
    unsigned char session_id_len;
    unsigned int cipher_suite_len;
    unsigned int compression_methods_len;

    // Check if the buffer has enough data to read the ServerHello message
    if (!SSL_peek(s, (char *)&n, 5)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the entire ServerHello message
    if (!SSL_read(s, (char *)&n, 5)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the length of the session ID
    if (!SSL_read(s, (char *)&session_id_len, 1)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the session ID
    if (!SSL_read(s, (char *)&s->session->session_id, session_id_len)) {
        return SSL_ERROR_SYSCALL;
    }
    s->session->session_id_length = session_id_len;

    // Read the length of the cipher suite
    if (!SSL_read(s, (char *)&cipher_suite_len, 2)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the cipher suite
    if (!SSL_read(s, (char *)&s->session->cipher, cipher_suite_len)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the length of the compression methods
    if (!SSL_read(s, (char *)&compression_methods_len, 1)) {
        return SSL_ERROR_SYSCALL;
    }

    // Read the compression methods
    if (!SSL_read(s, (char *)&s->session->compression, compression_methods_len)) {
        return SSL_ERROR_SYSCALL;
    }

    // Check if the ServerHello message is valid
    if (n != 5 + 1 + session_id_len + 2 + cipher_suite_len + 1 + compression_methods_len) {
        return SSL_ERROR_SSL;
    }

    return SSL_SUCCESS;
}
