typedef struct CALSImageHeader {
    unsigned char header[8]; /* CALS header signature */
    unsigned int width;
    unsigned int height;
    unsigned char bitsPerPixel;
} CALSImageHeader;

typedef struct CALSImageData {
    unsigned char *pixels;
} CALSImageData;

static MagickBooleanType ReadCALSImageHeader(Image *image, const void *blob, const size_t length)
{
    const unsigned char *p;
    CALSImageHeader header;

    p = (const unsigned char *) blob;
    if (length < sizeof(header))
        return(MagickFalse);
    memcpy(&header, p, sizeof(header));

    if (memcmp(header.header, "CALS", 4) != 0)
        return(MagickFalse);

    image->columns = header.width;
    image->rows = header.height;
    image->depth = header.bitsPerPixel;
    image->colors = 1 << header.bitsPerPixel;

    return(MagickTrue);
}

static MagickBooleanType ReadCALSImageData(Image *image, const void *blob, const size_t length)
{
    const unsigned char *p;
    CALSImageData data;
    size_t size;

    p = (const unsigned char *) blob;
    if (length < sizeof(data))
        return(MagickFalse);
    memcpy(&data, p, sizeof(data));

    size = image->columns * image->rows * (image->depth / 8);
    data.pixels = (unsigned char *) AcquireQuantumMemory(size, sizeof(unsigned char));
    if (data.pixels == (unsigned char *) NULL)
        return(MagickFalse);

    memcpy(data.pixels, p + sizeof(data), size);
    image->data = data.pixels;

    return(MagickTrue);
}

static Image *ReadCALSImage(const ImageInfo *image_info, ExceptionInfo *exception)
{
    Image *image;
    const void *blob;
    size_t length;

    image = AcquireImage(image_info, exception);
    if (image == (Image *) NULL)
        return((Image *) NULL);

    blob = GetBlob(image);
    length = GetBlobSize(image);

    if (!ReadCALSImageHeader(image, blob, length))
    {
        DestroyImage(image);
        return((Image *) NULL);
    }

    if (!ReadCALSImageData(image, blob, length))
    {
        DestroyImage(image);
        return((Image *) NULL);
    }

    return(image);
}

static ModuleExport ImageFormatModule cals_module = {
    "CALS",
    "ReadCALSImage",
    ReadCALSImage,
    NULL,
    NULL,
    NULL
};

ModuleExport const ImageFormatModule *GetImageFormatModule(void)
{
    return(&cals_module);
}
