#define INTR_INFO_INTR_TYPE_MASK 0x0000000F  // Mask for interrupt type
#define INTR_INFO_VALID_MASK 0x80000000      // Mask for validity of interrupt information

// Function to check if the interrupt information represents a hard exception
static inline bool is_exception(uint32_t intr_info) {
    // Check if the interrupt is valid and if the interrupt type is one of the hard exceptions
    return (intr_info & INTR_INFO_VALID_MASK) && ((intr_info & INTR_INFO_INTR_TYPE_MASK) == 0x03);
}
