#include <apr_thread_cond.h>
#include <apr_thread_mutex.h>
#include <apr_time.h>
#include <httpd.h>

struct h2_mplx {
    apr_thread_cond_t *cond;
    apr_thread_mutex_t *mutex;
    int cancel_all;
    int num_workers;
    apr_thread_t **workers;
};

void h2_mplx_release_and_join(struct h2_mplx *m) {
    if (m == NULL) {
        return;
    }

    // Signal all workers to cancel their tasks
    apr_thread_mutex_lock(m->mutex);
    m->cancel_all = 1;
    apr_thread_cond_broadcast(m->cond);
    apr_thread_mutex_unlock(m->mutex);

    // Wait for all workers to finish
    for (int i = 0; i < m->num_workers; ++i) {
        apr_thread_join(m->workers[i], NULL);
    }

    // Clean up resources
    apr_thread_cond_destroy(m->cond);
    apr_thread_mutex_destroy(m->mutex);
    for (int i = 0; i < m->num_workers; ++i) {
        apr_thread_join(m->workers[i], NULL);
    }
    free(m->workers);
    free(m);
}
