void set_ssl_options(MYSQL *conn, const char *ssl_ca, const char *ssl_cert, const char *ssl_key) {
    mysql_options(conn, MYSQL_OPT_SSL_CA, (char *)ssl_ca);
    mysql_options(conn, MYSQL_OPT_SSL_CERT, (char *)ssl_cert);
    mysql_options(conn, MYSQL_OPT_SSL_KEY, (char *)ssl_key);
