// Function to establish a secure MySQL connection
MYSQL *sql_real_connect(const char *host, const char *user, const char *passwd, const char *db, unsigned int port, const char *unix_socket, unsigned long client_flag) {
    MYSQL *conn = mysql_init(NULL);
    if (conn == NULL) {
        fprintf(stderr, "mysql_init() failed\n");
        return NULL;
    }

    // Set SSL options
    set_ssl_options(conn, "/path/to/ca.pem", "/path/to/cert.pem", "/path/to/key.pem");

    // Set connection parameters
    if (!mysql_real_connect(conn, host, user, passwd, db, port, unix_socket, client_flag)) {
        fprintf(stderr, "mysql_real_connect() failed: %s\n", mysql_error(conn));
        mysql_close(conn);
        return NULL;
    }

    // Set safe updates
    mysql_query(conn, "SET SQL_SAFE_UPDATES = 1");

    // Set charset
    if (mysql_set_character_set(conn, "utf8mb4") != 0) {
        fprintf(stderr, "mysql_set_character_set() failed: %s\n", mysql_error(conn));
        mysql_close(conn);
        return NULL;
    }

    return conn;
}

