#include <unsupported/Eigen/CXX11/Tensor>

namespace Eigen {
namespace internal {

template<typename Device, typename T, int Dims>
struct functor_traits<SpatialMaxPoolOp<Device, T, Dims>> {
  typedef void ReturnType;
};

template<typename Device, typename T, int Dims>
struct SpatialMaxPoolOp {
  EIGEN_DEVICE_FUNC EIGEN_STRONG_INLINE SpatialMaxPoolOp(const T* input, const int* kernel_size, const int* strides, const int* padding, T* output)
      : input_(input), kernel_size_(kernel_size), strides_(strides), padding_(padding), output_(output) {}

  template<typename Input, typename Output>
  EIGEN_DEVICE_FUNC EIGEN_STRONG_INLINE void operator()(const Eigen::array<Index, Dims>& coords) const {
    Index x = coords[0];
    Index y = coords[1];
    Index c = coords[2];

    Index output_x = (x + padding_[0]) / strides_[0];
    Index output_y = (y + padding_[1]) / strides_[1];

    if (output_x < 0 || output_x >= kernel_size_[0] || output_y < 0 || output_y >= kernel_size_[1]) {
      return; // Skip if out of bounds
    }

    T max_value = input_[x * input_shape_[1] * input_shape_[2] + y * input_shape_[2] + c];
    for (Index k = 0; k < kernel_size_[0]; ++k) {
      for (Index l = 0; l < kernel_size_[1]; ++l) {
        T value = input_[(x + k) * input_shape_[1] * input_shape_[2] + (y + l) * input_shape_[2] + c];
        if (value > max_value) {
          max_value = value;
        }
      }
    }
    output_[output_x * kernel_size_[1] * input_shape_[2] + output_y * input_shape_[2] + c] = max_value;
  }

  const T* input_;
  const int* kernel_size_;
  const int* strides_;
  const int* padding_;
  T* output_;
  Eigen::array<Index, Dims> input_shape_;
};

} // namespace internal
} // namespace Eigen

template<typename T, int Dims>
void SpatialMaxPool(const T* input, const int* kernel_size, const int* strides, const int* padding, T* output, const Eigen::array<Index, Dims>& input_shape) {
  Eigen::TensorMap<Eigen::Tensor<const T, Dims>> input_tensor(input, input_shape);
  Eigen::TensorMap<Eigen::Tensor<T, Dims>> output_tensor(output, input_shape);

  Eigen::SpatialMaxPoolOp<Eigen::DefaultDevice, T, Dims> op(input, kernel_size, strides, padding, output);
  output_tensor.device(Eigen::DefaultDevice()) = input_tensor.unaryExpr(op);
}
```

