    // Initialize LDAP connection
    if ((ld = ldap_init("ldap.example.com", LDAP_PORT)) == NULL) {
        perror("ldap_init");
        return -1;
    }

    // Bind to the LDAP directory
    if (ldap_simple_bind_s(ld, "cn=admin,dc=example,dc=com", "admin_password") != LDAP_SUCCESS) {
        perror("ldap_simple_bind_s");
        ldap_unbind_s(ld);
        return -1;
    }

    // Generate the distinguished name (DN) for the principal
    dn = ldap_get_dn(ld, principal);
    if (dn == NULL) {
        perror("ldap_get_dn");
        ldap_unbind_s(ld);
        return -1;
    }

    // Prepare the modifications
    mods[0] = (LDAPMod *)malloc(sizeof(LDAPMod));
    mods[0]->mod_type = "krbprincipalname";
    mods[0]->mod_op = LDAP_MOD_REPLACE;
    krbprincipalname = (char *)malloc(strlen(principal) + 1);
    strcpy(krbprincipalname, principal);
    mods[0]->mod_values = (char **)malloc(sizeof(char *));
    mods[0]->mod_values[0] = krbprincipalname;

    mods[1] = (LDAPMod *)malloc(sizeof(LDAPMod));
    mods[1]->mod_type = "krbLoginFailedCount";
    mods[1]->mod_op = LDAP_MOD_REPLACE;
    krbLoginFailedCount = (char *)malloc(10);
    sprintf(krbLoginFailedCount, "%d", 0);
    mods[1]->mod_values = (char **)malloc(sizeof(char *));
    mods[1]->mod_values[0] = krbLoginFailedCount;

    mods[2] = (LDAPMod *)malloc(sizeof(LDAPMod));
    mods[2]->mod_type = "krbLastPwdChange";
    mods[2]->mod_op = LDAP_MOD_REPLACE;
    krbLastPwdChange = (char *)malloc(20);
    time_t now = time(NULL);
    sprintf(krbLastPwdChange, "%ld", now);
    mods[2]->mod_values = (char **)malloc(sizeof(char *));
    mods[2]->mod_values[0] = krbLastPwdChange;

    mods[3] = (LDAPMod *)malloc(sizeof(LDAPMod));
    mods[3]->mod_type = "krbPasswordSalt";
    mods[3]->mod_op = LDAP_MOD_REPLACE;
    mods[3]->mod_values = (char **)malloc(sizeof(char *));
    mods[3]->mod_values[0] = (char *)"salt";

    mods[4] = NULL;

    // Modify the principal in LDAP
    if (ldap_modify_ext_s(ld, dn, mods, NULL, NULL) != LDAP_SUCCESS) {
        perror("ldap_modify_ext_s");
        ldap_unbind_s(ld);
        return -1;
    }

    // Free allocated memory
    for (int i = 0; i < 5; i++) {
        if (mods[i]) {
            free(mods[i]->mod_values[0]);
            free(mods[i]->mod_values);
            free(mods[i]);
        }
    }
    free(dn);
    free(krbprincipalname);
    free(krbLoginFailedCount);
    free(krbLastPwdChange);

    // Unbind from the LDAP directory
    ldap_unbind_s(ld);
    return 0;
}
