#include <stdio.h>
#include <string.h>
#include <talloc.h>
#include <notify.h>

struct change_notify {
    struct notify_context *ctx;
    struct notify_token *token;
    char *path;
};

struct change_notify *change_notify_create(TALLOC_CTX *mem_ctx, const char *path) {
    struct change_notify *notify = talloc_zero(mem_ctx, struct change_notify);
    if (!notify) {
        return NULL;
    }

    // Sanitize the path by removing trailing '/.'
    char *sanitized_path = talloc_strdup(notify, path);
    if (!sanitized_path) {
        talloc_free(notify);
        return NULL;
    }
    size_t len = strlen(sanitized_path);
    if (len > 2 && sanitized_path[len - 1] == '.' && sanitized_path[len - 2] == '/') {
        sanitized_path[len - 2] = '\0';
    }

    // Initialize the notification context
    notify->ctx = notify_init(notify);
    if (!notify->ctx) {
        talloc_free(notify);
        return NULL;
    }

    // Add a notification token for the sanitized path
    notify->token = notify_add(notify->ctx, sanitized_path, NOTIFY_CHANGE_INODE, NULL);
    if (!notify->token) {
        notify_fini(notify->ctx);
        talloc_free(notify);
        return NULL;
    }

    notify->path = sanitized_path;
    return notify;
}
