    TPM2B_DIGEST integrity;
    if (tpm2_calculate_integrity(&key_to_import, &integrity) != 0) {
        fprintf(stderr, "Failed to calculate integrity\n");
        tpm2_free_public_key(&parent_public);
        tpm2_free_private_key(&parent_private);
        tpm2_free_key(&key_to_import);
        tpm2_free_encrypted_key(&encrypted_key);
        return -1;
    }

    // Store the encrypted key and integrity
    if (tpm2_store_encrypted_key("encrypted_key.bin", &encrypted_key) != 0) {
        fprintf(stderr, "Failed to store encrypted key\n");
        tpm2_free_public_key(&parent_public);
        tpm2_free_private_key(&parent_private);
        tpm2_free_key(&key_to_import);
        tpm2_free_encrypted_key(&encrypted_key);
        tpm2_free_digest(&integrity);
