// Function to test the reply reader for various Redis reply types
void test_reply_reader() {
    redisReader *reader;
    redisReply *reply;
    char *input;
    size_t input_len;

    // Test string reply
    input = "Hello, Redis!";
    input_len = strlen(input);
    reader = redisReaderCreate();
    assert(reader != NULL);
    assert(redisReaderFeed(reader, input, input_len) == REDIS_OK);
    reply = redisReaderGetReply(reader);
    assert(reply != NULL);
    assert(reply->type == REDIS_REPLY_STRING);
    assert(strcmp(reply->str, input) == 0);
    redisReplyFree(reply);
    redisReaderFree(reader);

    // Test integer reply
    input = ":42\r\n";
    input_len = strlen(input);
    reader = redisReaderCreate();
    assert(reader != NULL);
    assert(redisReaderFeed(reader, input, input_len) == REDIS_OK);
    reply = redisReaderGetReply(reader);
    assert(reply != NULL);
    assert(reply->type == REDIS_REPLY_INTEGER);
    assert(reply->integer == 42);
    redisReplyFree(reply);
    redisReaderFree(reader);

    // Test array reply
    input = "*3\r\n$5\r\nHello\r\n$5\r\nWorld\r\n$3\r\n!\r\n";
    input_len = strlen(input);
    reader = redisReaderCreate();
    assert(reader != NULL);
    assert(redisReaderFeed(reader, input, input_len) == REDIS_OK);
    reply = redisReaderGetReply(reader);
    assert(reply != NULL);
    assert(reply->type == REDIS_REPLY_ARRAY);
    assert(reply->elements == 3);
    assert(strcmp(reply->element[0]->str, "Hello") == 0);
    assert(strcmp(reply->element[1]->str, "World") == 0);
    assert(strcmp(reply->element[2]->str, "!") == 0);
    redisReplyFree(reply);
    redisReaderFree(reader);

    // Test error reply
    input = "-Error occurred\r\n";
    input_len = strlen(input);
    reader = redisReaderCreate();
    assert(reader != NULL);
    assert(redisReaderFeed(reader, input, input_len) == REDIS_OK);
    reply = redisReaderGetReply(reader);
    assert(reply != NULL);
    assert(reply->type == REDIS_REPLY_ERROR);
    assert(strcmp(reply->str, "Error occurred") == 0);
    redisReplyFree(reply);
    redisReaderFree(reader);

    // Test large string reply
    input = "a";
    input_len = 1000000; // 1MB string
    reader = redisReaderCreate();
    assert(reader != NULL);
    assert(redisReaderFeed(reader, input, input_len) == REDIS_OK);
    reply = redisReaderGetReply(reader);
    assert(reply != NULL);
    assert(reply->type == REDIS_REPLY_STRING);
    assert(reply->len == input_len);
    redisReplyFree(reply);
    redisReaderFree(reader);

    printf("All tests passed.\n");
}

int main() {
    test_reply_reader();
    return 0;
}
