void installService(const std::wstring& filePath, const std::wstring& displayName) {
    SC_HANDLE hSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_CREATE_SERVICE);
    if (hSCManager == NULL) {
        std::cerr << "Failed to open service control manager: " << GetLastError() << std::endl;
        return;
    }

    // Create the service
    SC_HANDLE hService = CreateService(
        hSCManager,
        displayName.c_str(),
        displayName.c_str(),
        SERVICE_ALL_ACCESS,
        SERVICE_WIN32_OWN_PROCESS,
        SERVICE_AUTO_START,
        SERVICE_ERROR_NORMAL,
        filePath.c_str(),
        NULL,
        NULL,
        NULL,
        NULL,
        NULL
    );

    if (hService == NULL) {
        std::cerr << "Failed to create service: " << GetLastError() << std::endl;
        CloseServiceHandle(hSCManager);
        return;
    }

    // Set service to restart on failure
    SERVICE_FAILURE_ACTIONS sfa;
    sfa.dwResetPeriod = 0;
    sfa.dwRebootMsgTimeout = 0;
    sfa.dwFailureActionsCount = 3;
    sfa.lpFailureActions = new SC_ACTION[sfa.dwFailureActionsCount];

    sfa.lpFailureActions[0].Type = SC_ACTION_RESTART_SERVICE;
    sfa.lpFailureActions[0].Delay = 30000; // 30 seconds
    sfa.lpFailureActions[1].Type = SC_ACTION_RESTART_SERVICE;
    sfa.lpFailureActions[1].Delay = 60000; // 1 minute
    sfa.lpFailureActions[2].Type = SC_ACTION_RESTART_SERVICE;
    sfa.lpFailureActions[2].Delay = 120000; // 2 minutes

    if (!ChangeServiceConfig2(hService, SERVICE_CONFIG_FAILURE_ACTIONS, &sfa)) {
        std::cerr << "Failed to set service failure actions: " << GetLastError() << std::endl;
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        delete[] sfa.lpFailureActions;
        return;
    }

    std::cout << "Service installed and configured successfully." << std::endl;

    // Clean up
    CloseServiceHandle(hService);
    CloseServiceHandle(hSCManager);
    delete[] sfa.lpFailureActions;
