#include <mongoose.h>
#include <string>
#include <stdexcept>

class HTTPserver {
public:
    HTTPserver(int httpPort, int httpsPort, bool useSSL, const std::string& sslCertPath, const std::string& sslKeyPath);
    ~HTTPserver();

private:
    struct mg_mgr *mgr;
    struct mg_connection *nc;
    int httpPort;
    int httpsPort;
    bool useSSL;
    std::string sslCertPath;
    std::string sslKeyPath;
};

HTTPserver::HTTPserver(int httpPort, int httpsPort, bool useSSL, const std::string& sslCertPath, const std::string& sslKeyPath)
    : httpPort(httpPort), httpsPort(httpsPort), useSSL(useSSL), sslCertPath(sslCertPath), sslKeyPath(sslKeyPath) {
    mgr = mg_mgr_init();

    if (useSSL) {
        if (sslCertPath.empty() || sslKeyPath.empty()) {
            throw std::invalid_argument("SSL certificate or key path not provided");
        }
        nc = mg_bind_ssl(mgr, std::to_string(httpsPort).c_str(), nullptr, 0, sslCertPath.c_str(), sslKeyPath.c_str());
        if (!nc) {
            throw std::runtime_error("Failed to bind HTTPS port");
        }
    } else {
        nc = mg_bind(mgr, std::to_string(httpPort).c_str(), nullptr);
        if (!nc) {
            throw std::runtime_error("Failed to bind HTTP port");
        }
    }
}

HTTPserver::~HTTPserver() {
    mg_mgr_free(mgr);
}
```

