6. **Decode PKCS7 Data**: Decode the PKCS7 data using the BIOs and the decryption setup.
7. **Handle Detached Content**: Ensure that the detached content is handled correctly.
8. **Finalize Decoding**: Finalize the decoding process and clean up resources.

Here is a sample implementation of the `PKCS7_dataDecode` function:

```c
#include <openssl/pkcs7.h>
#include <openssl/bio.h>
#include <openssl/err.h>
#include <openssl/rand.h>
#include <stdio.h>
#include <stdlib.h>

void handleErrors() {
    ERR_print_errors_fp(stderr);
    abort();
}

int PKCS7_dataDecode(const unsigned char *pkcs7_data, size_t pkcs7_len, const unsigned char *detached_content, size_t detached_len, unsigned char **output, size_t *output_len) {
    BIO *in = NULL, *out = NULL, *pkcs7bio = NULL;
    PKCS7 *p7 = NULL;
    EVP_PKEY *pkey = NULL;
    int ret = 0;

    // Initialize OpenSSL
    OpenSSL_add_all_algorithms();
    ERR_load_crypto_strings();

    // Create BIOs
    in = BIO_new_mem_buf(pkcs7_data, pkcs7_len);
    if (!in) handleErrors();

    pkcs7bio = BIO_new(BIO_f_pkcs7());
    if (!pkcs7bio) handleErrors();

    out = BIO_new(BIO_s_mem());
    if (!out) handleErrors();

    // Set BIO chain
    in = BIO_push(pkcs7bio, in);

    // Read PKCS7 data
    p7 = d2i_PKCS7_bio(in, NULL);
    if (!p7) handleErrors();

    // Generate random key
    unsigned char key[32];
    if (!RAND_bytes(key, sizeof(key))) handleErrors();

    // Set up decryption
    pkey = EVP_PKEY_new_raw_private_key(EVP_PKEY_HMAC, NULL, key, sizeof(key));
    if (!pkey) handleErrors();

    // Decode PKCS7 data
    ret = PKCS7_decrypt(p7, pkey, NULL, out, PKCS7_DETACHED, 0);
    if (!ret) handleErrors();

    // Handle detached content
    if (detached_content) {
        BIO *detached_bio = BIO_new_mem_buf(detached_content, detached_len);
        if (!detached_bio) handleErrors();

        BIO *detached_out = BIO_new(BIO_s_mem());
        if (!detached_out) handleErrors();

        // Set BIO chain for detached content
        detached_bio = BIO_push(detached_bio, detached_out);

        // Process detached content
        ret = PKCS7_verify(p7, NULL, NULL, detached_bio, out, PKCS7_DETACHED);
        if (!ret) handleErrors();

        // Get output length
        *output_len = BIO_get_mem_data(out, NULL);
        *output = malloc(*output_len);
        if (!*output) handleErrors();
        BIO_read(out, *output, *output_len);
    } else {
        // Get output length
        *output_len = BIO_get_mem_data(out, NULL);
        *output = malloc(*output_len);
        if (!*output) handleErrors();
        BIO_read(out, *output, *output_len);
    }

    // Clean up
    PKCS7_free(p7);
    EVP_PKEY_free(pkey);
    BIO_free_all(in);
    BIO_free_all(pkcs7bio);
    BIO_free_all(out);

    return ret;
}

int main() {
    unsigned char pkcs7_data[] = { /* Your PKCS7 data here */ };
    size_t pkcs7_len = sizeof(pkcs7_data);
    unsigned char detached_content[] = { /* Your detached content here */ };
    size_t detached_len = sizeof(detached_content);
    unsigned char *output = NULL;
    size_t output_len = 0;

    int ret = PKCS7_dataDecode(pkcs7_data, pkcs7_len, detached_content, detached_len, &output, &output_len);
    if (ret) {
        printf("Decoded data: %.*s\n", (int)output_len, output);
        free(output);
    } else {
        printf("Decoding failed\n");
    }

    return 0;
}
```

### Explanation:
1. **Initialization**: OpenSSL is initialized with `OpenSSL_add_all_algorithms` and `ERR_load_crypto_strings`.
2. **BIOs**: BIOs are created for reading the PKCS7 data and for output.
3. **PKCS7 Data Reading**: The PKCS7 data is read into a `PKCS7` structure.
4. **Random Key Generation**: A random key is generated using `RAND_bytes`.
5. **Decryption Setup**: An `EVP_PKEY` is created with the generated key.
6. **Decoding**: The PKCS7 data is decrypted and the output is stored in a BIO.
7. **Detached Content Handling**: If detached content is provided, it is processed to ensure the integrity of the PKCS7 data.
8. **Cleanup**: Resources are cleaned up to avoid memory leaks.

This implementation ensures that the PKCS7 data is securely decoded and handles detached content correctly, providing a defense against MMA attacks through random key generation.
